SELECT COUNT(DISTINCT S.PK_SIAPE) AS TOTAL_SERVIDORES FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA C ON S.PK_SIAPE = C.SIAPE WHERE C.ANO = 2021 AND C.SEMESTRE = 1 AND UPPER(C.SIGLA_CAMPUS) = 'OES' AND UPPER(S.CONTRATO) = 'EFETIVOS' AND (UPPER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%CIENCIA DA COMPUTACAO%' OR UPPER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%CIENCIA DA COMPUTACAO%' OR UPPER(COALESCE(S.AREA_INGRESSO_OG,'')) LIKE '%CIENCIA DA COMPUTACAO%' OR UPPER(COALESCE(S.AREA_INGRESSO_OG,'')) LIKE '%CIENCIA DA COMPUTACAO%' OR UPPER(COALESCE(C.AREA_INGRESSO,'')) LIKE '%CIENCIA DA COMPUTACAO%' OR UPPER(COALESCE(C.AREA_INGRESSO,'')) LIKE '%CIENCIA DA COMPUTACAO%')